class ETGProFormaInvoiceCanadaController extends SrsReportRunController
{
    SalesAgreementHeader salesAgreementHeader;
    ETGProFormaInvoiceCanadaContract   contract;
}

Method.Source:
public static ETGProFormaInvoiceCanadaController construct()
{
    return new ETGProFormaInvoiceCanadaController();
}

/// <summary>
/// entry point for running the report
/// </summary>
/// <param name = "_args">Args _args</param>
public static void main(Args _args)
{
    ETGProFormaInvoiceCanadaController controller = new ETGProFormaInvoiceCanadaController();
    controller.parmArgs(_args);
    controller.parmReportName(ssrsReportStr(ETGProFormaInvoiceCanadaReport, Design));
    controller.parmShowDialog(false);
    controller.parmDialogCaption("Proforma sales invoice canada");
    controller.startOperation();
}

/// <summary>
/// modify contract for custom design
/// </summary>
protected void preRunModifyContract()
{
    str reportnameLocal;
    contract = this.parmReportContract().parmRdpContract();
    this.getReportContract().parmReportCaption("Proforma sales invoice canada.");

    switch (args.record().TableId)
    {
        case  tableNum(SalesAgreementHeader):
            salesAgreementHeader =  args.record();
            contract.parmSalesAgreementId(salesAgreementHeader.SalesNumberSequence);
            reportnameLocal = ssrsReportStr(ETGProFormaInvoiceCanadaReport, Design);
            break;
        default:
            throw error(Error::wrongUseOfFunction(funcName()));
    }
    this.parmReportName(reportnameLocal);
    this.parmReportContract().parmReportName(this.parmReportName());
}
